        mode = self.im.getpalettemode()
        mode_len = len(mode)
        palette = self.im.getpalette(mode, mode)
        num_colors = len(palette) // mode_len
        colors = [
            tuple(palette[i * mode_len : (i + 1) * mode_len])
            for i in range(num_colors)
        ]

        if sort_palette == "luminance":

            def sort_key(color):
                r, g, b = color[:3]
                return r * 299 + g * 587 + b * 114

        else:

            def sort_key(color):
                return color[:3]

        # Only the palette entries actually used by a pixel are meaningful;
        # the rest are unused filler left over from quantization. Sort the
        # used entries and leave the filler ones in their original order,
        # appended at the end, so that used colors are grouped predictably
        # at the start of the palette.
        histogram = self.histogram()[:num_colors]
        used = [i for i in range(num_colors) if histogram[i]]
        unused = [i for i in range(num_colors) if not histogram[i]]
        order = sorted(used, key=lambda i: sort_key(colors[i])) + unused"}

